namespace sv_c227acbf7cb544d89e710055ce8d1ee6.Services;

public class WizardState
{
    // Step 1: Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3: References
    public List<ReferenceEntry> References { get; set; } = [];

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = [];
    public int CurrentStep { get; set; } = 1;

    public const int TotalSteps = 4;
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceEntry
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;

namespace sv_c227acbf7cb544d89e710055ce8d1ee6.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by session ID.
/// Both the static SSR layout and interactive pages resolve the same
/// instance, so they share state through the session-cookie key.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
        => _states.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId)
        => _states.TryRemove(sessionId, out _);
}

