arguments.new_str:
﻿@inherits LayoutComponentBase
@using sv_c227acbf7cb544d89e710055ce8d1ee6.Services
@inject WizardStateService WizardService
@inject IHttpContextAccessor HttpContextAccessor

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (_isWizardRoute)
            {
                <div class="d-flex align-items-center gap-3 flex-grow-1">
                    <strong>Step @_state!.CurrentStep of @WizardState.TotalSteps</strong>
                    <div class="progress flex-grow-1" style="height: 8px;">
                        <div class="progress-bar"
                             role="progressbar"
                             style="width: @(_state.CurrentStep * 100 / WizardState.TotalSteps)%">
                        </div>
                    </div>
                    @foreach (var step in Enumerable.Range(1, WizardState.TotalSteps))
                    {
                        <span class="badge @(_state.CompletedSteps.Contains(step) ? "bg-success" : (step == _state.CurrentStep ? "bg-primary" : "bg-secondary"))">
                            @step
                        </span>
                    }
                </div>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private bool _isWizardRoute;
    private WizardState? _state;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is null) return;

        var path = httpContext.Request.Path.Value ?? "";
        _isWizardRoute = path.StartsWith("/apply", StringComparison.OrdinalIgnoreCase);

        if (_isWizardRoute)
        {
            var sessionId = GetOrCreateSessionId(httpContext);
            _state = WizardService.GetOrCreate(sessionId);
        }
    }

    private static string GetOrCreateSessionId(HttpContext httpContext)
    {
        const string cookieName = "WizardSessionId";

        if (httpContext.Request.Cookies.TryGetValue(cookieName, out var existing)
            && !string.IsNullOrEmpty(existing))
        {
            return existing;
        }

        var newId = Guid.NewGuid().ToString("N");
        httpContext.Response.Cookies.Append(cookieName, newId, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(2)
        });
        return newId;
    }
}

