@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_c227acbf7cb544d89e710055ce8d1ee6.Services
@inject WizardStateService WizardService
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Nav
@implements IDisposable

<PageTitle>Apply - Personal Info</PageTitle>
<h3>Step 1: Personal Information</h3>

@if (_state is not null)
{
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <input class="form-control" @bind="_state.Name" @bind:event="oninput" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <input class="form-control" type="email" @bind="_state.Email" @bind:event="oninput" />
    </div>
    <button class="btn btn-primary" @onclick="Next">Next: Experience →</button>
}

@code {
    private WizardState? _state;
    private string? _sessionId;
    private PersistingComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        _sub = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            _sessionId = restored;
        }
        else
        {
            // During prerendering, HttpContext is available
            var httpContext = HttpContextAccessor.HttpContext;
            _sessionId = httpContext?.Request.Cookies["WizardSessionId"];
        }

        if (_sessionId is not null)
        {
            _state = WizardService.GetOrCreate(_sessionId);
            _state.CurrentStep = 1;
        }
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("wizardSessionId", _sessionId);
        return Task.CompletedTask;
    }

    private void Next()
    {
        _state!.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }

    public void Dispose() => _sub.Dispose();
}

