@page "/apply/review"
@rendermode InteractiveServer
@using sv_c227acbf7cb544d89e710055ce8d1ee6.Services
@inject WizardStateService WizardService
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Nav
@implements IDisposable

<PageTitle>Apply - Review</PageTitle>
<h3>Step 4: Review Your Application</h3>

@if (_state is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @_state.Name</p>
        <p><strong>Email:</strong> @_state.Email</p>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (_state.Jobs.Count == 0)
        {
            <p class="text-muted">No jobs added.</p>
        }
        @foreach (var job in _state.Jobs)
        {
            <p>@job.Title at @job.Company (@job.Years years)</p>
        }
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (_state.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        @foreach (var r in _state.References)
        {
            <p>@r.Name — @r.Relationship — @r.Phone</p>
        }
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">Application submitted!</div>
    }
}

@code {
    private WizardState? _state;
    private string? _sessionId;
    private bool _submitted;
    private PersistingComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        _sub = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
            _sessionId = restored;
        else
            _sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];

        if (_sessionId is not null)
        {
            _state = WizardService.GetOrCreate(_sessionId);
            _state.CurrentStep = 4;
        }
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("wizardSessionId", _sessionId);
        return Task.CompletedTask;
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        _state!.CompletedSteps.Add(4);
        _submitted = true;
        // In production: save to DB, then call WizardService.Remove(_sessionId!)
    }

    public void Dispose() => _sub.Dispose();
}

