+        <button class="btn btn-secondary" @onclick="Back">← Back</button>
+        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
+    </div>
+
+    @if (_submitted)
+    {
+        <div class="alert alert-success mt-3">Application submitted!</div>
+    }
+}
+
+@code {
+    private WizardState? _state;
+    private string? _sessionId;
+    private bool _submitted;
+    private PersistingComponentStateSubscription _sub;
+
+    protected override void OnInitialized()
+    {
+        _sub = PersistentState.RegisterOnPersisting(PersistState);
+
+        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
+            _sessionId = restored;
+        else
+            _sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
+
+        if (_sessionId is not null)
+        {
+            _state = WizardService.GetOrCreate(_sessionId);
+            _state.CurrentStep = 4;
+        }
+    }
+
+    private Task PersistState()
+    {
+        PersistentState.PersistAsJson("wizardSessionId", _sessionId);
+        return Task.CompletedTask;
+    }
+
+    private void Back() => Nav.NavigateTo("/apply/references");
+
+    private void Submit()
+    {
+        _state!.CompletedSteps.Add(4);
+        _submitted = true;
+        // In production: save to DB, then call WizardService.Remove(_sessionId!)
+    }
+
+    public void Dispose() => _sub.Dispose();
+}
+
